/**
 * Calculates (base^exponent) % modulus efficiently.
 * @param {bigint} base 
 * @param {bigint} exponent 
 * @param {bigint} modulus 
 * @returns {bigint}
 */
const power = (base, exponent, modulus) => {
    let res = 1n;
    base %= modulus;
    while (exponent > 0n) {
        if (exponent % 2n === 1n) {
            res = (res * base) % modulus;
        }
        base = (base * base) % modulus;
        exponent /= 2n;
    }
    return res;
};

/**
 * Precomputes factorials and inverse factorials for combinations.
 * @param {number} maxN 
 * @param {bigint} MOD 
 * @returns {{fact: bigint[], invFact: bigint[]}}
 */
const precomputeFactorials = (maxN, MOD) => {
    const fact = new Array(maxN + 1);
    const invFact = new Array(maxN + 1);
    fact[0] = 1n;
    for (let i = 1; i <= maxN; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }

    // Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
    invFact[maxN] = power(fact[maxN], MOD - 2n, MOD);
    for (let i = maxN - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * BigInt(i + 1)) % MOD;
    }
    return { fact, invFact };
};

/**
 * Calculates nCk % MOD.
 * @param {number} n 
 * @param {number} k 
 * @param {bigint} MOD 
 * @param {{fact: bigint[], invFact: bigint[]}} precomputed 
 * @returns {bigint}
 */
const nCr = (n, k, MOD, precomputed) => {
    if (k < 0 || k > n) {
        return 0n;
    }
    if (k === 0 || k === n) {
        return 1n;
    }
    if (k > n / 2) {
        k = n - k;
    }
    const { fact, invFact } = precomputed;
    // nCk = n! / (k! * (n-k)!)
    let res = fact[n];
    res = (res * invFact[k]) % MOD;
    res = (res * invFact[n - k]) % MOD;
    return res;
};


/**
 * @param {number} n
 * @param {number} pos
 * @param {number} k
 * @return {number}
 */
function solve(n, pos, k) {
    const MOD = 1000000000 + 7;
    const MOD_BIGINT = BigInt(MOD);

    // Number of people to the left of pos (indices 0 to pos-1)
    const L_count = pos; 
    // Number of people to the right of pos (indices pos+1 to n-1)
    const R_count = n - 1 - pos;

    // --- Analysis of visibility ---
    // 1. For i < pos (Left side, size L_count):
    //    - Visible if person i chooses 'L'.
    //    - Not visible if person i chooses 'R'.
    //    - We need exactly 'l' people from the left to see pos.
    //    - Number of ways to choose 'l' people out of L_count to be 'L' is C(L_count, l).

    // 2. For i > pos (Right side, size R_count):
    //    - Visible if person i chooses 'R'.
    //    - Not visible if person i chooses 'L'.
    //    - We need exactly 'r' people from the right to see pos.
    //    - Number of ways to choose 'r' people out of R_count to be 'R' is C(R_count, r).

    // The total visible count must be k: l + r = k.

    // 3. The person at pos (index pos) can choose 'L' or 'R' (2 ways), regardless of the count k.

    // Precompute combinations up to n
    const precomputed = precomputeFactorials(n, MOD_BIGINT);

    let totalWays = 0n;

    // Iterate over the number of people seen from the left (l)
    // l must be in [0, L_count] and l <= k
    for (let l = 0; l <= L_count; l++) {
        // The required number seen from the right (r) is k - l
        const r = k - l;

        // Check if r is valid: 0 <= r <= R_count
        if (r < 0 || r > R_count) {
            continue;
        }

        // Ways to achieve l from left: C(L_count, l)
        const waysL = nCr(L_count, l, MOD_BIGINT, precomputed);

        // Ways to achieve r from right: C(R_count, r)
        const waysR = nCr(R_count, r, MOD_BIGINT, precomputed);

        // Total ways for this specific split (l, r) = waysL * waysR
        const waysForLR = (waysL * waysR) % MOD_BIGINT;

        // Contribution to total ways: waysForLR * (Ways for pos)
        // Ways for pos = 2 (chooses 'L' or 'R')
        const contribution = (waysForLR * 2n) % MOD_BIGINT;

        totalWays = (totalWays + contribution) % MOD_BIGINT;
    }

    return Number(totalWays);
}

