fn solve(n: i64, pos: i64, k: i64) -> i64 {
    let modulus: i64 = 1_000_000_007;
    let n_usize = n as usize;
    let pos_usize = pos as usize;
    let k_usize = k as usize;

    // Modular exponentiation: (base^exponent) % modulus
    fn power(base: i64, exponent: i64, modulus: i64) -> i64 {
        let mut res = 1;
        let mut base = base % modulus;
        let mut exp = exponent;
        while exp > 0 {
            if exp % 2 == 1 {
                res = (res * base) % modulus;
            }
            base = (base * base) % modulus;
            exp /= 2;
        }
        res
    }

    // Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
    fn mod_inverse(n: i64, modulus: i64) -> i64 {
        power(n, modulus - 2, modulus)
    }

    // Precompute factorials and inverse factorials
    let mut fact = vec![1; n_usize + 1];
    let mut inv_fact = vec![1; n_usize + 1];
    for i in 1..=n_usize {
        fact[i] = (fact[i - 1] * i as i64) % modulus;
    }
    inv_fact[n_usize] = mod_inverse(fact[n_usize], modulus);
    for i in (0..n_usize).rev() {
        inv_fact[i] = (inv_fact[i + 1] * (i + 1) as i64) % modulus;
    }

    // nCk % MOD
    fn ncr(n: usize, r: usize, fact: &[i64], inv_fact: &[i64], modulus: i64) -> i64 {
        if r > n {
            return 0;
        }
        let num = fact[n];
        let den = (inv_fact[r] * inv_fact[n - r]) % modulus;
        (num * den) % modulus
    }

    // Number of people to the left of pos (indices 0 to pos-1)
    let l_count = pos_usize;
    // Number of people to the right of pos (indices pos+1 to n-1)
    let r_count = n_usize - 1 - pos_usize;

    let mut total_ways: i64 = 0;

    // Iterate over the number of people seen from the left (l)
    // l must be in [0, L_count] and l <= k_usize
    for l in 0..=l_count {
        // The required number seen from the right (r) is k_usize - l
        let r = k_usize.saturating_sub(l);

        // Check if r is valid: 0 <= r <= R_count
        if r > r_count {
            continue;
        }

        // Ways to achieve l from left: C(L_count, l)
        let ways_l = ncr(l_count, l, &fact, &inv_fact, modulus);

        // Ways to achieve r from right: C(R_count, r)
        let ways_r = ncr(r_count, r, &fact, &inv_fact, modulus);

        // Total ways for this specific split (l, r) = waysL * waysR
        let ways_for_lr = (ways_l * ways_r) % modulus;

        // Contribution to total ways: waysForLR * (Ways for pos)
        // Ways for pos = 2 (chooses 'L' or 'R')
        let contribution = (ways_for_lr * 2) % modulus;

        total_ways = (total_ways + contribution) % modulus;
    }

    total_ways
}
