 * Calculates (base^exponent) % modulus efficiently.
 * @param {bigint} base 
 * @param {bigint} exponent 
 * @param {bigint} modulus 
 * @returns {bigint}
 */
const power = (base, exponent, modulus) => {
    let res = 1n;
    base %= modulus;
    while (exponent > 0n) {
        if (exponent % 2n === 1n) {
            res = (res * base) % modulus;
        }
        base = (base * base) % modulus;
        exponent /= 2n;
    }
    return res;
};

/**
 * Precomputes factorials and inverse factorials for combinations.
 * @param {number} maxN 
 * @param {bigint} MOD 
 * @returns {{fact: bigint[], invFact: bigint[]}}
 */
const precomputeFactorials = (maxN, MOD) => {
    const fact = new Array(maxN + 1);
    const invFact = new Array(maxN + 1);
    fact[0] = 1n;
    for (let i = 1; i <= maxN; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }

    // Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
    invFact[maxN] = power(fact[maxN], MOD - 2n, MOD);
    for (let i = maxN - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * BigInt(i + 1)) % MOD;
    }
    return { fact, invFact };
