    const MOD_BIGINT = BigInt(MOD);

    // Number of people to the left of pos (indices 0 to pos-1)
    const L_count = pos; 
    // Number of people to the right of pos (indices pos+1 to n-1)
    const R_count = n - 1 - pos;

    // --- Analysis of visibility ---
    // 1. For i < pos (Left side, size L_count):
    //    - Visible if person i chooses 'L'.
    //    - Not visible if person i chooses 'R'.
    //    - We need exactly 'l' people from the left to see pos.
    //    - Number of ways to choose 'l' people out of L_count to be 'L' is C(L_count, l).

    // 2. For i > pos (Right side, size R_count):
    //    - Visible if person i chooses 'R'.
    //    - Not visible if person i chooses 'L'.
    //    - We need exactly 'r' people from the right to see pos.
    //    - Number of ways to choose 'r' people out of R_count to be 'R' is C(R_count, r).

    // The total visible count must be k: l + r = k.

    // 3. The person at pos (index pos) can choose 'L' or 'R' (2 ways), regardless of the count k.

    // Precompute combinations up to n
    const precomputed = precomputeFactorials(n, MOD_BIGINT);

