        const r = k - l;

        // Check if r is valid: 0 <= r <= R_count
        if (r < 0 || r > R_count) {
            continue;
        }

        // Ways to achieve l from left: C(L_count, l)
        const waysL = nCr(L_count, l, MOD_BIGINT, precomputed);

        // Ways to achieve r from right: C(R_count, r)
        const waysR = nCr(R_count, r, MOD_BIGINT, precomputed);

        // Total ways for this specific split (l, r) = waysL * waysR
        const waysForLR = (waysL * waysR) % MOD_BIGINT;

        // Contribution to total ways: waysForLR * (Ways for pos)
        // Ways for pos = 2 (chooses 'L' or 'R')
        const contribution = (waysForLR * 2n) % MOD_BIGINT;

        totalWays = (totalWays + contribution) % MOD_BIGINT;
    }

    return Number(totalWays);
