// Modular exponentiation: (base^exponent) % modulus
fn power(mut base: i64, mut exp: i64, modulus: i64) -> i64 {
    let mut res = 1;
    base %= modulus;
    while exp > 0 {
        if exp % 2 == 1 {
            res = (res as i128 * base as i128 % modulus as i128) as i64;
        }
        base = (base as i128 * base as i128 % modulus as i128) as i64;
        exp /= 2;
    }
    res
}

// Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
fn mod_inverse(n: i64, modulus: i64) -> i64 {
    power(n, modulus - 2, modulus)
}

// Structure to hold precomputed factorials and inverse factorials
struct Factorials {
    fact: Vec<i64>,
    inv_fact: Vec<i64>,
}

impl Factorials {
    // Precomputes factorials and inverse factorials up to max_n
    fn new(max_n: usize, modulus: i64) -> Self {
        let mut fact = vec![1; max_n + 1];
        for i in 1..=max_n {
            fact[i] = (fact[i - 1] as i128 * i as i128 % modulus as i128) as i64;
        }

        let mut inv_fact = vec![0; max_n + 1];
        inv_fact[max_n] = mod_inverse(fact[max_n], modulus);

        for i in (0..max_n).rev() {
            inv_fact[i] = (inv_fact[i + 1] as i128 * (i + 1) as i128 % modulus as i128) as i64;
        }

        Factorials { fact, inv_fact }
    }

    // Calculates nCk % MOD
    fn ncr(&self, n: usize, k: usize, modulus: i64) -> i64 {
        if k > n {
            return 0;
        }
        // nCk = n! / (k! * (n-k)!)
        let num = self.fact[n];
        let den = (self.inv_fact[k] as i128 * self.inv_fact[n - k] as i128 % modulus as i128) as i64;

        (num as i128 * den as i128 % modulus as i128) as i64
    }
}

