// Helper function for modular exponentiation (a^b % m)
fn power(mut base: i64, mut exponent: i64, modulus: i64) -> i64 {
    let mut res = 1;
    base %= modulus;
    while exponent > 0 {
        if exponent % 2 == 1 {
            res = ((res as i128 * base as i128) % modulus as i128) as i64;
        }
        base = ((base as i128 * base as i128) % modulus as i128) as i64;
        exponent /= 2;
    }
    res
}

// Helper function for modular inverse using Fermat's Little Theorem
// Requires modulus to be prime
fn mod_inverse(n: i64, modulus: i64) -> i64 {
    power(n, modulus - 2, modulus)
}

// Structure to hold precomputed factorials and inverse factorials
struct Combinatorics {
    fact: Vec<i64>,
    inv_fact: Vec<i64>,
    modulus: i64,
}

impl Combinatorics {
    fn new(max_n: usize, modulus: i64) -> Combinatorics {
        let mut fact = vec![0; max_n + 1];
        let mut inv_fact = vec![0; max_n + 1];

        fact[0] = 1;
        for i in 1..=max_n {
            fact[i] = ((fact[i - 1] as i128 * i as i128) % modulus as i128) as i64;
        }

        // Compute inverse of fact[max_n] first
        inv_fact[max_n] = mod_inverse(fact[max_n], modulus);

        // Compute the rest of the inverse factorials iteratively
        for i in (0..max_n).rev() {
            // inv_fact[i] = inv_fact[i+1] * (i+1) % MOD
            let next_val = (inv_fact[i + 1] as i128 * (i + 1) as i128) % modulus as i128;
            inv_fact[i] = next_val as i64;
        }

        Combinatorics {
            fact,
            inv_fact,
            modulus,
        }
    }

    // Calculates nCk % MOD
    fn ncr(&self, n: i64, k: i64) -> i64 {
        if k < 0 || k > n {
            return 0;
        }
        let n_usize = n as usize;
        let k_usize = k as usize;

