        let num = self.fact[n_usize];
        let den1 = self.inv_fact[k_usize];
        let den2 = self.inv_fact[n_usize - k_usize];

        let res = (num as i128 * den1 as i128) % self.modulus as i128;
        ((res * den2 as i128) % self.modulus as i128) as i64
    }
}


